**Finding:** `GET /users` returns a list of user records (names + email addresses) with zero authentication or authorization. Any anonymous caller on the network can enumerate all users.

**Risk:** OWASP A01 – Broken Access Control, OWASP A02 – Cryptographic Failures (data exposure)

**Fix:** Add an authentication middleware before the route. Example using JWT:

```js
const jwt = require('jsonwebtoken');

function requireAuth(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Bearer <token>
  if (!token) return res.status(401).json({ error: 'Unauthorized' });

  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET);
    next();
  } catch {
    return res.status(403).json({ error: 'Forbidden' });
  }
}

// Apply to the route
