const { z } = require('zod');

const app = express();
app.use(express.json());           // parse JSON bodies
app.use(express.urlencoded({ extended: false })); // parse form bodies

// Example: validate query params
const UserQuerySchema = z.object({
  page:  z.coerce.number().int().min(1).default(1),
  limit: z.coerce.number().int().min(1).max(100).default(20),
});

app.get('/users', requireAuth, (req, res) => {
  const result = UserQuerySchema.safeParse(req.query);
  if (!result.success) return res.status(400).json({ error: result.error.format() });
  // use result.data.page, result.data.limit
});
